let ideConfig = null;
const PROXY_MARKER = '/conduit-proxy/';

self.addEventListener('message', (event) => {
    if (event.data.type === 'SYNC_CONFIG') {
        ideConfig = event.data.config;
        console.log("🛡️ SW Config Synced", ideConfig);
    }
});

self.addEventListener('install', () => self.skipWaiting());
self.addEventListener('activate', (event) => event.waitUntil(clients.claim()));

self.addEventListener('fetch', (event) => {
    const url = event.request.url;
    if (url.includes(PROXY_MARKER) && ideConfig) {
        const targetUrl = url.split(PROXY_MARKER)[1];
        event.respondWith(handleProxyRequest(targetUrl));
    }
});

async function handleProxyRequest(targetUrl) {
    try {
        // Tunnel the request through the Edge Function to bypass CORS
        const res = await fetch(ideConfig.funcUrl, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                action: 'proxy_web',
                url: targetUrl,
                repo_name: ideConfig.repoName
            })
        });

        const contentType = res.headers.get('Content-Type');

        // Inject the logging bridge if it's an HTML page
        if (contentType && contentType.includes('text/html')) {
            let html = await res.text();
            const bridge = `
                <script>
                (function() {
                    const originalConsole = { ...console };
                    ['log','warn','error','info'].forEach(m => {
                        console[m] = (...args) => {
                            window.parent.postMessage({ type: 'CONDUIT_LOG', method: m, args: args.map(String), time: new Date().toLocaleTimeString() }, '*');
                            originalConsole[m](...args);
                        };
                    });
                    document.addEventListener('click', e => {
                        const a = e.target.closest('a');
                        if(a && a.href && !a.href.startsWith('#')) {
                            e.preventDefault();
                            window.parent.postMessage({ type: 'CONDUIT_NAVIGATE', url: a.href }, '*');
                        }
                    }, true);
                })();
                </script>`;
            return new Response(html.replace('<head>', '<head>' + bridge), {
                headers: { 'Content-Type': 'text/html' }
            });
        }

        return res;
    } catch (e) {
        return new Response("Proxy Tunnel Failure: " + e.message, { status: 500 });
    }
}

